        newCost := dispatch.Assigns[assignIdx].Cost
        if newCost < 0 {
            dispatch.Assigns[assignIdx].RemoveShip(shipID)
            dispatch.Assigns[assignIdx].GenRoute()
            return -1
        }
        delta := newCost - origCost
        // rollback for now; we'll apply the chosen one later
        dispatch.Assigns[assignIdx].RemoveShip(shipID)
        dispatch.Assigns[assignIdx].GenRoute()
        return delta
    }

    // Try each order
    for jj := range oris {
        shipID := total_ship + jj
        bestDelta := math.MaxFloat64
        bestAssignIdx := -1

