Modified greedy best-fit insertion with fallback seed expansion: For each ship order, evaluate all existing non-empty assigns plus one empty assign candidate using a weighted cost heuristic considering distance increase and time window feasibility, insert into the minimal-cost feasible assign, and if none accepts, expand fleet by initializing a new assign with the order while preserving original assign integrity.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    const EMPTY_ASSIGN_INDEX = -1
    type cand struct {
        idx       int
        costInc   float64
        feasible  bool
    }

    // Mark existing non‑empty assigns
    nonEmptyIndices := make([]int, 0, dispatch.AssignsLen)
    for i := 0; i < dispatch.AssignsLen; i++ {
        if dispatch.Assigns[i].StationsLen > 0 {
            nonEmptyIndices = append(nonEmptyIndices, i)
        }
    }

    for jj := range oris {
        shipID := total_ship + jj
        var bestCand cand
        bestCand.idx = EMPTY_ASSIGN_INDEX
        bestCand.costInc = 1e18
        bestCand.feasible = false

        // Evaluate insertion into every existing non‑empty assign
        for _, i := range nonEmptyIndices {
            snapshotCost := dispatch.Assigns[i].Cost
            ok := dispatch.Assigns[i].AddShip(shipID, oris[jj], dess[jj])
            if ok {
                dispatch.Assigns[i].GenRoute()
                if dispatch.Assigns[i].Cost >= 0 {
                    costInc := dispatch.Assigns[i].Cost - snapshotCost
                    if costInc < bestCand.costInc {
                        bestCand.idx = i
                        bestCand.costInc = costInc
                        bestCand.feasible = true
                    }
                }
                dispatch.Assigns[i].RemoveShip(shipID)
                dispatch.Assigns[i].Cost = snapshotCost
                dispatch.Assigns[i].GenRoute()
            }
        }

        // Evaluate a fresh empty assign if there is room
        if dispatch.AssignsLen < MAXASSIGNS && len(nonEmptyIndices) == 0 || true {
            i := dispatch.AssignsLen
            // Snapshot current state (should be zero)
            snapshotCost := dispatch.Assigns[i].Cost
            ok := dispatch.Assigns[i].AddShip(shipID, oris[jj], dess[jj])
            if ok {
                dispatch.Assigns[i].GenRoute()
                if dispatch.Assigns[i].Cost >= 0 {
                    costInc := dispatch.Assigns[i].Cost - snapshotCost
                    if costInc < bestCand.costInc {
                        bestCand.idx = i
                        bestCand.costInc = costInc
                        bestCand.feasible = true
                    }
                }
                dispatch.Assigns[i].RemoveShip(shipID)
                dispatch.Assigns[i].Cost = snapshotCost
                dispatch.Assigns[i].GenRoute()
            }
        }

        // Perform the chosen insertion
        if bestCand.feasible {
            if bestCand.idx >= dispatch.AssignsLen {
                // New assign creation (seed‑style expansion)
                dispatch.Assigns[bestCand.idx].AddShip(shipID, oris[jj], dess[jj])
                dispatch.Assigns[bestCand.idx].GenRoute()
                dispatch.AssignsLen++
            } else {
                dispatch.Assigns[bestCand.idx].AddShip(shipID, oris[jj], dess[jj])
                dispatch.Assigns[bestCand.idx].GenRoute()
            }
        } else {
            // Fallback seed insertion: create a brand‑new assign even if beyond current AssignsLen
            // (the previous loop already checked the next free slot; we force it here for safety)
            if dispatch.AssignsLen < MAXASSIGNS {
                i := dispatch.AssignsLen
                dispatch.Assigns[i].AddShip(shipID, oris[jj], dess[jj])
                dispatch.Assigns[i].GenRoute()
                dispatch.AssignsLen++
            }
        }

        // Update non‑empty indices after potential new assign creation
        if dispatch.AssignsLen > len(nonEmptyIndices) {
            nonEmptyIndices = make([]int, 0, dispatch.AssignsLen)
            for i := 0; i < dispatch.AssignsLen; i++ {
                if dispatch.Assigns[i].StationsLen > 0 {
                    nonEmptyIndices = append(nonEmptyIndices, i)
                }
            }
        }
    }

    dispatch.RenewnTotalCost()
    return dispatch

